use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Compares two real numbers with respect to the six most significant digits.
/// Returns "LT" if a < b, "EQ" if a == b, or "GT" if a > b.
pub fn realcompare(a: f64, b: f64) -> &'static str {
    // Scale both numbers to have 6 significant digits as integers
    let scale = |x: f64| -> i64 {
        if x == 0.0 {
            return 0;
        }
        let abs_x = x.abs();
        let digits = abs_x.log10().ceil() as i32;
        let factor = 10f64.powi(6 - digits);
        (x * factor).round() as i64
    };

    let scaled_a = scale(a);
    let scaled_b = scale(b);

    if scaled_a < scaled_b {
        "LT"
    } else if scaled_a > scaled_b {
        "GT"
    } else {
        "EQ"
    }
}

/// Returns the quadrant (0=I, 1=II, 2=III, 3=IV) for a point (x, y).
/// Priority: I > II > III > IV for ambiguous points.
fn quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) == "LT" {
        // x < 0: quadrants II or III
        if realcompare(y, 0.0) == "LT" {
            2 // III
        } else {
            1 // II (y >= 0, including y == 0)
        }
    } else {
        // x >= 0: quadrants I or IV
        if realcompare(y, 0.0) == "LT" {
            2 // III for (0, -1) per spec, actually IV would be 3
            // Wait, let me re-read: point (0,-1) is in quadrant III per spec
            // That's wrong by standard convention but let me re-read spec
            // Spec says: (0,0) in I, (-1,0) in II, (0,-1) in III, (0,1) in I, (1,0) in I
        } else {
            0 // I
        }
    }
}

// Re-reading spec: (0,-1) is in quadrant III which is unusual
// Standard: I (+,+), II (-,+), III (-,-), IV (+,-)
// But spec says (0,-1) is in III, which breaks standard convention
// Let me re-read more carefully:
// (0,0) is in I, (-1,0) is in II, (0,-1) is in III, (0,1) is in I, (1,0) is in I
// This means: when x=0, use I for y>=0, III for y<0
// This is non-standard but matches the spec example
fn quadrant_spec(x: f64, y: f64) -> usize {
    let x_lt_zero = realcompare(x, 0.0) == "LT";
    let y_lt_zero = realcompare(y, 0.0) == "LT";
    let x_eq_zero = realcompare(x, 0.0) == "EQ";
    let y_eq_zero = realcompare(y, 0.0) == "EQ";

    if x_lt_zero {
        // x < 0
        if y_lt_zero {
            2 // III
        } else {
            1 // II (y >= 0)
        }
    } else if x_eq_zero {
        // x == 0
        if y_lt_zero {
            2 // III per spec: (0,-1) is in III
        } else {
            0 // I per spec: (0,0), (0,1) are in I
        }
    } else {
        // x > 0
        if y_lt_zero {
            3 // IV - wait, but spec doesn't give an example
            // Actually let me check: (0,-1) is III, so (+, -) would be IV
            // Standard says IV, but let me verify with the pattern
            // The spec examples suggest standard quadrants with special handling for x=0
            // (0,0)->I, (-1,0)->II, (0,-1)->III, (0,1)->I, (1,0)->I
            // So: x>0, y<0 should be IV
            3 // IV
        } else {
            0 // I
        }
    }
}

/// Compute the distance between two points.
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

/// Compute the area of a triangle given three vertices.
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

/// Compute the angle at vertex (vx, vy) formed by rays to (x1, y1) and (x2, y2).
/// Returns None if either ray point coincides with the vertex.
fn angle_at_vertex(vx: f64, vy: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> Option<f64> {
    // Check if either point coincides with vertex
    if realcompare(x1, vx) == "EQ" && realcompare(y1, vy) == "EQ" {
        return None;
    }
    if realcompare(x2, vx) == "EQ" && realcompare(y2, vy) == "EQ" {
        return None;
    }

    let dx1 = x1 - vx;
    let dy1 = y1 - vy;
    let dx2 = x2 - vx;
    let dy2 = y2 - vy;

    let len1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let len2 = (dx2 * dx2 + dy2 * dy2).sqrt();

    if realcompare(len1, 0.0) == "EQ" || realcompare(len2, 0.0) == "EQ" {
        return None;
    }

    // Compute angle using dot product: cos(angle) = (a·b) / (|a||b|)
    let dot = dx1 * dx2 + dy1 * dy2;
    let cos_angle = dot / (len1 * len2);

    // Clamp to [-1, 1] to handle numerical errors
    let cos_angle = cos_angle.max(-1.0).min(1.0);

    Some(cos_angle.acos())
}

/// Check if three points can be contained within or on a circle of given radius.
/// Uses the fact that three points define a unique circle (unless collinear).
fn can_contain_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // Compute distances between points
    let a = distance(x2, y2, x3, y3);
    let b = distance(x1, y1, x3, y3);
    let c = distance(x1, y1, x2, y2);

    // Check if points are collinear (area ~ 0)
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if realcompare(area, 0.0) == "EQ" {
        // Points are collinear - the smallest circle containing them
        // has diameter equal to the maximum distance between any two points
        let max_dist = a.max(b).max(c);
        let required_radius = max_dist / 2.0;
        return realcompare(required_radius, radius) != "GT";
    }

    // For non-collinear points, compute circumradius
    // R = (a * b * c) / (4 * area)
    let circumradius = (a * b * c) / (4.0 * area);

    realcompare(circumradius, radius) != "GT"
}

/// Compute the distance from point (px, py) to the line through (x1, y1) and (x2, y2).
fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    // If line is just a point, return distance to that point
    if realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ" {
        return distance(px, py, x1, y1);
    }

    // Line: ax + by + c = 0
    // Distance = |ax0 + by0 + c| / sqrt(a^2 + b^2)
    let a = y2 - y1;
    let b = x1 - x2;
    let c = x2 * y1 - x1 * y2;

    let numerator = (a * px + b * py + c).abs();
    let denominator = (a * a + b * b).sqrt();

    numerator / denominator
}

/// Evaluate LIC 1: Two consecutive points with distance > LENGTH1.
fn lic_1(input: &DecideInput) -> bool {
    if realcompare(input.parameters.length1, 0.0) == "LT" {
        return false; // Constraint violated, but spec says assume valid inputs
    }

    for i in 0..input.numpoints.saturating_sub(1) {
        let d = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 2: Three consecutive points not containable in circle of RADIUS1.
fn lic_2(input: &DecideInput) -> bool {
    if realcompare(input.parameters.radius1, 0.0) == "LT" {
        return false;
    }

    for i in 0..input.numpoints.saturating_sub(2) {
        if !can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
            input.parameters.radius1
        ) {
            return true;
        }
    }
    false
}

/// Evaluate LIC 3: Three consecutive points forming angle < PI-EPSILON or > PI+EPSILON.
fn lic_3(input: &DecideInput) -> bool {
    if realcompare(input.parameters.epsilon, 0.0) == "LT" ||
       realcompare(input.parameters.epsilon, PI) != "LT" {
        return false;
    }

    let pi_minus_eps = PI - input.parameters.epsilon;
    let pi_plus_eps = PI + input.parameters.epsilon;

    for i in 0..input.numpoints.saturating_sub(2) {
        if let Some(angle) = angle_at_vertex(
            input.x[i + 1], input.y[i + 1],
            input.x[i], input.y[i],
            input.x[i + 2], input.y[i + 2]
        ) {
            if realcompare(angle, pi_minus_eps) == "LT" ||
               realcompare(angle, pi_plus_eps) == "GT" {
                return true;
            }
        }
    }
    false
}

/// Evaluate LIC 4: Three consecutive points forming triangle with area > AREA1.
fn lic_4(input: &DecideInput) -> bool {
    if realcompare(input.parameters.area1, 0.0) == "LT" {
        return false;
    }

    for i in 0..input.numpoints.saturating_sub(2) {
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2]
        );
        if realcompare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 5: Q_PTS consecutive points in more than QUADS quadrants.
fn lic_5(input: &DecideInput) -> bool {
    if input.parameters.q_pts < 2 || input.parameters.q_pts > input.numpoints {
        return false;
    }
    if input.parameters.quads < 1 || input.parameters.quads > 3 {
        return false;
    }

    for start in 0..=input.numpoints.saturating_sub(input.parameters.q_pts) {
        let mut quadrants_used = [false; 4];
        for i in 0..input.parameters.q_pts {
            let idx = start + i;
            let q = quadrant_spec(input.x[idx], input.y[idx]);
            quadrants_used[q] = true;
        }
        let count = quadrants_used.iter().filter(|&&x| x).count();
        if count > input.parameters.quads {
            return true;
        }
    }
    false
}

/// Evaluate LIC 6: Two consecutive points where X[j] - X[i] < 0 (i = j - 1).
fn lic_6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints.saturating_sub(1) {
        let j = i + 1;
        let diff = input.x[j] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 7: N_PTS consecutive points, at least one > DIST from line joining first and last.
fn lic_7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    if input.parameters.n_pts < 3 || input.parameters.n_pts > input.numpoints {
        return false;
    }
    if realcompare(input.parameters.dist, 0.0) == "LT" {
        return false;
    }

    for start in 0..=input.numpoints.saturating_sub(input.parameters.n_pts) {
        let end = start + input.parameters.n_pts - 1;
        let x_first = input.x[start];
        let y_first = input.y[start];
        let x_last = input.x[end];
        let y_last = input.y[end];

        for i in (start + 1)..end {
            let d = point_to_line_distance(input.x[i], input.y[i], x_first, y_first, x_last, y_last);
            if realcompare(d, input.parameters.dist) == "GT" {
                return true;
            }
        }
    }
    false
}

/// Evaluate LIC 8: Two points separated by K_PTS intervening points with distance > LENGTH1.
fn lic_8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    if input.parameters.k_pts < 1 || input.parameters.k_pts > input.numpoints - 2 {
        return false;
    }
    if realcompare(input.parameters.length1, 0.0) == "LT" {
        return false;
    }

    // Points separated by exactly K_PTS consecutive intervening points
    // means indices i and i + K_PTS + 1
    let k = input.parameters.k_pts;
    for i in 0..input.numpoints.saturating_sub(k + 1) {
        let j = i + k + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, input.parameters.length1) == "GT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 9: Three points separated by A_PTS and B_PTS not containable in circle of RADIUS1.
fn lic_9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    if input.parameters.a_pts < 1 || input.parameters.b_pts < 1 {
        return false;
    }
    if input.parameters.a_pts + input.parameters.b_pts > input.numpoints - 3 {
        return false;
    }
    if realcompare(input.parameters.radius1, 0.0) == "LT" {
        return false;
    }

    let a = input.parameters.a_pts;
    let b = input.parameters.b_pts;

    // Points at i, i+A_PTS+1, i+A_PTS+B_PTS+2
    for i in 0..input.numpoints.saturating_sub(a + b + 2) {
        let j = i + a + 1;
        let k = j + b + 1;
        if !can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            input.parameters.radius1
        ) {
            return true;
        }
    }
    false
}

/// Evaluate LIC 10: Three points separated by C_PTS and D_PTS forming angle outside [PI-EPSILON, PI+EPSILON].
fn lic_10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    if input.parameters.c_pts < 1 || input.parameters.d_pts < 1 {
        return false;
    }
    if input.parameters.c_pts + input.parameters.d_pts > input.numpoints - 3 {
        return false;
    }
    if realcompare(input.parameters.epsilon, 0.0) == "LT" ||
       realcompare(input.parameters.epsilon, PI) != "LT" {
        return false;
    }

    let c = input.parameters.c_pts;
    let d = input.parameters.d_pts;
    let pi_minus_eps = PI - input.parameters.epsilon;
    let pi_plus_eps = PI + input.parameters.epsilon;

    // Points at i, i+C_PTS+1, i+C_PTS+D_PTS+2
    // Second point is the vertex
    for i in 0..input.numpoints.saturating_sub(c + d + 2) {
        let vertex_idx = i + c + 1;
        let last_idx = vertex_idx + d + 1;

        if let Some(angle) = angle_at_vertex(
            input.x[vertex_idx], input.y[vertex_idx],
            input.x[i], input.y[i],
            input.x[last_idx], input.y[last_idx]
        ) {
            if realcompare(angle, pi_minus_eps) == "LT" ||
               realcompare(angle, pi_plus_eps) == "GT" {
                return true;
            }
        }
    }
    false
}

/// Evaluate LIC 11: Three points separated by E_PTS and F_PTS forming triangle with area > AREA1.
fn lic_11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    if input.parameters.e_pts < 1 || input.parameters.f_pts < 1 {
        return false;
    }
    if input.parameters.e_pts + input.parameters.f_pts > input.numpoints - 3 {
        return false;
    }
    if realcompare(input.parameters.area1, 0.0) == "LT" {
        return false;
    }

    let e = input.parameters.e_pts;
    let f = input.parameters.f_pts;

    // Points at i, i+E_PTS+1, i+E_PTS+F_PTS+2
    for i in 0..input.numpoints.saturating_sub(e + f + 2) {
        let j = i + e + 1;
        let k = j + f + 1;
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );
        if realcompare(area, input.parameters.area1) == "GT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 12: Two points separated by G_PTS with X[j] - X[i] < 0.
fn lic_12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    if input.parameters.g_pts < 1 || input.parameters.g_pts > input.numpoints - 2 {
        return false;
    }

    let g = input.parameters.g_pts;
    for i in 0..input.numpoints.saturating_sub(g + 1) {
        let j = i + g + 1;
        let diff = input.x[j] - input.x[i];
        if realcompare(diff, 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// Evaluate LIC 13: Points separated by K_PTS with dist > LENGTH1 AND dist < LENGTH2.
fn lic_13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    if input.parameters.k_pts < 1 || input.parameters.k_pts > input.numpoints - 2 {
        return false;
    }
    if realcompare(input.parameters.length1, 0.0) == "LT" ||
       realcompare(input.parameters.length2, 0.0) == "LT" {
        return false;
    }

    let k = input.parameters.k_pts;
    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..input.numpoints.saturating_sub(k + 1) {
        let j = i + k + 1;
        let d = distance(input.x[i], input.y[i], input.x[j], input.y[j]);

        if realcompare(d, input.parameters.length1) == "GT" {
            found_gt = true;
        }
        if realcompare(d, input.parameters.length2) == "LT" {
            found_lt = true;
        }

        if found_gt && found_lt {
            return true;
        }
    }
    false
}

/// Evaluate LIC 14: Three points with A_PTS, B_PTS not in RADIUS1 AND in RADIUS2.
fn lic_14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    if input.parameters.a_pts < 1 || input.parameters.b_pts < 1 {
        return false;
    }
    if input.parameters.a_pts + input.parameters.b_pts > input.numpoints - 3 {
        return false;
    }
    if realcompare(input.parameters.radius1, 0.0) == "LT" ||
       realcompare(input.parameters.radius2, 0.0) == "LT" {
        return false;
    }

    let a = input.parameters.a_pts;
    let b = input.parameters.b_pts;
    let mut found_not_in_r1 = false;
    let mut found_in_r2 = false;

    for i in 0..input.numpoints.saturating_sub(a + b + 2) {
        let j = i + a + 1;
        let k = j + b + 1;

        let in_r1 = can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            input.parameters.radius1
        );
        let in_r2 = can_contain_in_circle(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
            input.parameters.radius2
        );

        if !in_r1 {
            found_not_in_r1 = true;
        }
        if in_r2 {
            found_in_r2 = true;
        }

        if found_not_in_r1 && found_in_r2 {
            return true;
        }
    }
    false
}

/// Evaluate LIC 15: Three points with E_PTS, F_PTS forming triangle with area > AREA1 AND < AREA2.
fn lic_15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    if input.parameters.e_pts < 1 || input.parameters.f_pts < 1 {
        return false;
    }
    if input.parameters.e_pts + input.parameters.f_pts > input.numpoints - 3 {
        return false;
    }
    if realcompare(input.parameters.area1, 0.0) == "LT" ||
       realcompare(input.parameters.area2, 0.0) == "LT" {
        return false;
    }

    let e = input.parameters.e_pts;
    let f = input.parameters.f_pts;
    let mut found_gt = false;
    let mut found_lt = false;

    for i in 0..input.numpoints.saturating_sub(e + f + 2) {
        let j = i + e + 1;
        let k = j + f + 1;
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k]
        );

        if realcompare(area, input.parameters.area1) == "GT" {
            found_gt = true;
        }
        if realcompare(area, input.parameters.area2) == "LT" {
            found_lt = true;
        }

        if found_gt && found_lt {
            return true;
        }
    }
    false
}

/// Compute the Conditions Met Vector (CMV).
fn compute_cmv(input: &DecideInput) -> Vec<bool> {
    vec![
        lic_1(input),
        lic_2(input),
        lic_3(input),
        lic_4(input),
        lic_5(input),
        lic_6(input),
        lic_7(input),
        lic_8(input),
        lic_9(input),
        lic_10(input),
        lic_11(input),
        lic_12(input),
        lic_13(input),
        lic_14(input),
        lic_15(input),
    ]
}

/// Compute the Preliminary Unlocking Matrix (PUM).
fn compute_pum(input: &DecideInput, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];

    // Fill diagonal from input.pum_diag
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }

    // Fill off-diagonal from LCM and CMV
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }

            let connector = &input.lcm[i][j];
            pum[i][j] = match connector.as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false, // Should not happen with valid inputs
            };
        }
    }

    pum
}

/// Compute the Final Unlocking Vector (FUV).
fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    let mut fuv = vec![false; 15];

    for i in 0..15 {
        // FUV[i] is true if PUM[i,i] is false, or if all elements in row i are true
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    fuv
}

/// Main decide function implementing the Launch Interceptor Program.
pub fn decide(input: &DecideInput) -> DecideOutput {
    // Compute CMV
    let cmv = compute_cmv(input);

    // Compute PUM
    let pum = compute_pum(input, &cmv);

    // Compute FUV
    let fuv = compute_fuv(&pum);

    // Compute LAUNCH: all FUV elements must be true
    let launch = fuv.iter().all(|&x| x);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
